1	-- -------------------------------------------------------------------------------------------------
2	-- Copyright (c) Lukas Vik. All rights reserved.
3	--
4	-- This file is part of the hdl-modules project, a collection of reusable, high-quality,
5	-- peer-reviewed VHDL building blocks.
6	-- https://hdl-modules.com
7	-- https://github.com/hdl-modules/hdl-modules
8	-- -------------------------------------------------------------------------------------------------
9	-- BFM for sending data on an AXI-Stream interface.
10	--
11	-- Data is pushed to the ``data_queue`` :doc:`VUnit queue <vunit:data_types/queue>` as a
12	-- :doc:`VUnit integer_array <vunit:data_types/integer_array>`.
13	-- Each element in the integer array should be an unsigned byte.
14	-- Little endian byte order is assumed.
15	--
16	--
17	-- Randomization
18	-- _____________
19	--
20	-- This BFM can inject random handshake stall/jitter, for good verification coverage.
21	-- Modify the ``stall_config`` generic to get your desired behavior.
22	-- The random seed is provided by a VUnit mechanism
23	-- (see the "seed" portion of `this document <https://vunit.github.io/run/user_guide.html>`__).
24	-- Use the ``--seed`` command line argument if you need to set a static seed.
25	--
26	--
27	-- Unaligned packet length
28	-- _______________________
29	--
30	-- The byte length of the packets (as indicated by the length of the ``data_queue`` arrays)
31	-- does not need to be aligned with the ``data_width`` of the bus.
32	-- If unaligned, the last data beat will not have all byte lanes set to valid
33	-- ``data`` and ``strobe``.
34	--
35	--
36	-- User signalling
37	-- _______________
38	--
39	-- This BFM optionally supports sending auxiliary data on the ``user`` port also.
40	-- Enable by setting a non-zero ``user_width`` and a valid ``user_queue``.
41	-- User data is pushed as a :doc:`VUnit integer_array <vunit:data_types/integer_array>`
42	-- just as for the regular data.
43	-- The length of packets must be the same as what is pushed to the ``data_queue``.
44	-- -------------------------------------------------------------------------------------------------
45	
46	library ieee;
47	use ieee.numeric_std.all;
48	use ieee.std_logic_1164.all;
49	
50	library vunit_lib;
51	use vunit_lib.check_pkg.all;
52	use vunit_lib.integer_array_pkg.all;
53	use vunit_lib.queue_pkg.all;
54	
55	use work.stall_bfm_pkg.all;
56	
57	library common;
58	use common.types_pkg.all;
59	
60	
61	entity axi_stream_master is
62	  generic (
63	    -- Set the desired width of the 'data' field.
64	    data_width : positive;
65	    -- Push data (integer_array_t with push_ref()) to this queue.
66	    -- The integer arrays will be deallocated after this BFM is done with them.
67	    data_queue : queue_t;
68	    -- Optionally enable the 'user' port by setting a non-zero width here.
69	    -- Must also set the 'user_queue' generic to a valid queue.
70	    user_width : natural := 0;
71	    -- Push auxiliary user data (integer_array_t with push_ref()) to this queue.
72	    -- Must also se the 'user_width' generic to a non-zero value.
73	    -- The integer arrays will be deallocated after this BFM is done with them.
74	    user_queue : queue_t := null_queue;
75	    -- Assign non-zero to randomly insert jitter/stalling in the data stream.
76	    stall_config : stall_configuration_t := zero_stall_configuration;
77	    -- Suffix for error log messages. Can be used to differentiate between multiple instances.
78	    logger_name_suffix : string := "";
79	    -- The 'strobe' is usually a "byte strobe", but the strobe unit width can be modified for cases
80	    -- when the strobe lanes are wider than bytes.
81	    strobe_unit_width : positive := 8;
82	    -- When 'valid' is zero, the associated output ports will be driven with this value.
83	    -- This is to avoid a DUT sampling the values in the wrong clock cycle.
84	    drive_invalid_value : std_ulogic := 'X'
85	  );
86	  port (
87	    clk : in std_ulogic;
88	    --# {{}}
89	    ready : in std_ulogic;
90	    valid : out std_ulogic := '0';
91	    last : out std_ulogic := drive_invalid_value;
92	    data : out std_ulogic_vector(data_width - 1 downto 0) := (others => drive_invalid_value);
93	    strobe : out std_ulogic_vector(data_width / strobe_unit_width - 1 downto 0) := (
94	      others => drive_invalid_value
95	    );
96	    user : out std_ulogic_vector(user_width - 1 downto 0) := (others => drive_invalid_value);
97	    --# {{}}
98	    num_packets_sent : out natural := 0
99	  );
100	end entity;
101	
102	architecture a of axi_stream_master is
103	
104	  constant base_error_message : string := " - axi_stream_master" & logger_name_suffix;
105	
106	  constant bytes_per_beat : positive := data_width / 8;
107	  constant bytes_per_strobe_unit : positive := strobe_unit_width / 8;
108	
109	  signal last_int : std_ulogic := drive_invalid_value;
110	  signal data_int : std_ulogic_vector(data'range) := (others => drive_invalid_value);
111	  signal strobe_byte : std_ulogic_vector(data_width / 8 - 1 downto 0) := (others => '0');
112	  signal strobe_int : std_ulogic_vector(data_width / strobe_unit_width - 1 downto 0) := (
113	    others => '0'
114	  );
115	
116	  signal data_is_valid : std_ulogic := '0';
117	
118	begin
119	
120	  assert data_width mod 8 = 0 report (
121	    base_error_message
122	    & ": This entity works on a byte-by-byte basis. Data width must be a multiple of bytes."
123	  );
124	
125	  assert data_width mod strobe_unit_width = 0
126	    report base_error_message & ": A whole number of strobes must fit in each beat.";
127	
128	  assert data_width >= strobe_unit_width
129	    report base_error_message & "Strobe unit can not be greater than data width.";
130	
131	  assert strobe_unit_width mod 8 = 0
132	    report base_error_message & ": Strobe unit must be a byte multiple";
133	
134	  assert strobe_unit_width >= 8
135	    report base_error_message & ": Strobe unit must be one byte or wider";
136	
137	
138	  ------------------------------------------------------------------------------
139	  main : process
140	    variable data_packet : integer_array_t := null_integer_array;
141	    variable packet_length_bytes : positive := 1;
142	    variable data_value : natural := 0;
143	
144	    variable byte_lane_idx : natural range 0 to bytes_per_beat - 1 := 0;
145	    variable is_last_byte : boolean := false;
146	  begin
147	    while is_empty(data_queue) loop
148	      wait until rising_edge(clk);
149	    end loop;
150	
151	    data_packet := pop_ref(data_queue);
152	    packet_length_bytes := length(data_packet);
153	
154	    assert packet_length_bytes mod bytes_per_strobe_unit = 0
155	      report base_error_message & ": Packet length must be a multiple of strobe unit";
156	
157	    data_is_valid <= '1';
158	
159	    for byte_idx in 0 to packet_length_bytes - 1 loop
160	      byte_lane_idx := byte_idx mod bytes_per_beat;
161	
162	      data_value := get(arr=>data_packet, idx=>byte_idx);
163	      data_int((byte_lane_idx + 1) * 8 - 1 downto byte_lane_idx * 8) <=
164	        std_ulogic_vector(to_unsigned(data_value, 8)
165	      );
166	
167	      strobe_byte(byte_lane_idx) <= '1';
168	
169	      is_last_byte := byte_idx = packet_length_bytes - 1;
170	
171	      if byte_lane_idx = bytes_per_beat - 1 or is_last_byte then
172	        last_int <= to_sl(is_last_byte);
173	
174	        wait until ready and valid and rising_edge(clk);
175	
176	        -- Default for next beat. We will fill in the byte lanes that are used.
177	        data_int <= (others => drive_invalid_value);
178	        strobe_byte <= (others => '0');
179	      end if;
180	    end loop;
181	
182	    -- Deallocate after we are done with the data.
183	    deallocate(data_packet);
184	
185	    -- Default: Signal "not valid" to handshake BFM before next packet.
186	    -- If queue is not empty, it will instantly be raised again (no bubble cycle).
187	    data_is_valid <= '0';
188	
189	    num_packets_sent <= num_packets_sent + 1;
190	  end process;
191	
192	
193	  ------------------------------------------------------------------------------
194	  handshake_master_inst : entity work.handshake_master
195	    generic map(
196	      stall_config => stall_config
197	    )
198	    port map(
199	      clk => clk,
200	      --
201	      data_is_valid => data_is_valid,
202	      --
203	      ready => ready,
204	      valid => valid
205	    );
206	
207	
208	  ------------------------------------------------------------------------------
209	  assign_byte_strobe : if strobe_unit_width = 8 generate
210	
211	    strobe_int <= strobe_byte;
212	
213	  else generate
214	
215	    ------------------------------------------------------------------------------
216	    assign : process(all)
217	    begin
218	      for strobe_idx in strobe'range loop
219	        strobe_int(strobe_idx) <= strobe_byte(strobe_idx * bytes_per_strobe_unit);
220	      end loop;
221	    end process;
222	
223	  end generate;
224	
225	
226	  ------------------------------------------------------------------------------
227	  assign_invalid : process(all)
228	  begin
229	    -- We should drive the 'invalid' value when bus is not valid.
230	
231	    if valid then
232	      last <= last_int;
233	      data <= data_int;
234	      strobe <= strobe_int;
235	    else
236	      last <= drive_invalid_value;
237	      data <= (others => drive_invalid_value);
238	      strobe <= (others => drive_invalid_value);
239	    end if;
240	  end process;
